-- Seed de clientes GPA con correos de ejecutivos y gerentes
-- Generado automáticamente desde Clientes_GPA_Portal_Garantías.xlsx
-- Ejecutar: psql $DATABASE_URL -f seed_clientes.sql

CREATE TABLE IF NOT EXISTS clientes_config (
  sap_cliente_id   TEXT PRIMARY KEY,
  nombre           TEXT NOT NULL,
  email_ejecutivo  TEXT,
  email_gerente    TEXT,
  sucursal         TEXT,
  estatus          TEXT NOT NULL DEFAULT 'Activo',
  actualizado_en   TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Insertar/actualizar todos los clientes (upsert)
ON CONFLICT (sap_cliente_id) DO UPDATE SET
  nombre          = EXCLUDED.nombre,
  email_ejecutivo = EXCLUDED.email_ejecutivo,
  email_gerente   = EXCLUDED.email_gerente,
  sucursal        = EXCLUDED.sucursal,
  estatus         = EXCLUDED.estatus,
  actualizado_en  = NOW();

-- Total: 2092 clientes (1403 activos, 689 inactivos)